using namespace std;

class Solution {
public:
    string robotWithString(string s) {
        int n = s.size();
        if (n == 0) return "";

        vector<char> min_right(n + 1, 127); // Initialize with a high value

        for (int i = n-1; i >= 0; --i) {
            min_right[i] = min(s[i], min_right[i+1]);
        }

        stack<char> stk;
        string res;

        for (int i = 0; i < n; ++i) {
            stk.push(s[i]);
            while (!stk.empty() && stk.top() <= min_right[i+1]) {
                res += stk.top();
                stk.pop();
            }
        }

        // Pop remaining elements
        while (!stk.empty()) {
            res += stk.top();
            stk.pop();
        }

        return res;
    }
};

